  const cProp = editable ? undefined : onProp;

  /* contrast-safe text colors using luminance */
  const lum=hex=>{const h=hex.replace("#","");const r=parseInt(h.substring(0,2),16),g=parseInt(h.substring(2,4),16),bl=parseInt(h.substring(4,6),16);return(r*299+g*587+bl*114)/1000;};
  const onAc=lum(p.ac)>150?"#1a1a1a":"#fff";
